// src/pages/Login.jsx
import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import '../styles/style.css';

const ADMIN = { email: 'admin@mostafa.com', password: 'Admin123!' };

export default function Login() {
  const navigate = useNavigate();
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [name, setName] = useState('');
  const [error, setError] = useState('');

  useEffect(() => {
    if (localStorage.getItem('isLoggedIn') === 'true') navigate('/home');
  }, [navigate]);

  const handleLogin = (e) => {
    e.preventDefault();
    if (!email || !password) return setError('Please enter your email and password.');

    const isAdmin = email === ADMIN.email && password === ADMIN.password;
    const role = isAdmin ? 'admin' : 'customer';

    localStorage.setItem('isLoggedIn', 'true');
    localStorage.setItem('userRole', role);

    if (role === 'customer') {
      const users = JSON.parse(localStorage.getItem('users')) || [];
      if (!users.find(u => u.email === email)) {
        users.push({ name: name || email.split('@')[0], email });
        localStorage.setItem('users', JSON.stringify(users));
      }
    }

    navigate('/home');
  };

  return (
    <div className="login-page">
      <div className="login-card">
        <h2>Welcome Back</h2>
        <p>Sign in to Mostafa Restaurant</p>

        <form onSubmit={handleLogin} className="login-form">
          <input
            type="text"
            placeholder="Your Name (optional)"
            value={name}
            onChange={(e) => setName(e.target.value)}
            className="login-input"
          />
          <input
            type="email"
            placeholder="Email"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            className="login-input"
            required
          />
          <input
            type="password"
            placeholder="Password"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            className="login-input"
            required
          />

          {error && <p className="login-error">{error}</p>}
          <button type="submit" className="login-btn">Login</button>
        </form>

        <p className="login-info">
          Admin credentials: <strong>admin@mostafa.com / Admin123!</strong>
        </p>
      </div>
    </div>
  );
}
